var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0713: <color=#ffd34c>주시윤</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS006M0713：<color=#ffd34c>アキヤマ・シリュウ</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0713: <color=#ffd34c>Joo Shiyoon.</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0713: <color=#ffd34c>周時雲</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"주시윤. 만 18세.","JPN":"アキヤマ・シリュウ。満18歳。","ENG":"Joo Shiyoon. 18 years old.","TWN":"周時雲，18歲。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"펜릴 소대 제 2기 선발 견습 대원.","JPN":"フェンリル小隊第2期先発研修隊員。","ENG":"Picked up during the second trainee draft of the Fenrir Squad.","TWN":"芬里爾小隊第2期選拔的見習隊員。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그리고 현재 유일하게 남은 정규 대원이라.......","JPN":"そして現在唯一残った正規隊員か……","ENG":"And the only remaining regular member of the squad...","TWN":"而且是現在唯一剩下的正規隊員……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이 친구가 바로 회사의 미래를 짊어진 젊은 새싹이로군.","JPN":"この若者こそ、わが社の未来を担う新芽と言えるだろう。","ENG":"He is the young sprout that will lead the company in the future.","TWN":"這位朋友就是肩負公司未來的幼苗啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......그야 독버섯도 새싹이라면 새싹이겠죠.","JPN":"……例えそれが毒キノコであろうと、新芽は新芽でしょうね。","ENG":"Only that he is a sprout of a poisonous mushroom.","TWN":"……如果毒蘑菇也算幼苗的的話，那就當他是幼苗吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그동안 쌓인 게 많은 것 같군.","JPN":"彼と色々あったような物言いだな。","ENG":"You seem to have something against him.","TWN":"看來這段時間，你內心累積了很多不滿呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"딱히 모난 성격으로 보이진 않는데.......","JPN":"特に角のある性格には見えないが……","ENG":"He doesn't seem like the type to cause trouble...","TWN":"他的個性看起來沒有那麼難相處啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무슨 사고라도 친 건가?","JPN":"何かやらかしたのか？","ENG":"Has he done something?","TWN":"是闖了什麼禍嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"말씀하신 대로 성격 자체에는 문제가 없습니다.","JPN":"おっしゃるとおり、性格自体に問題はありません。","ENG":"As you said, he's definitely not a troublemaker.","TWN":"如您所說，他的個性本身沒有問題。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"붙임성도 좋고 머리 회전도 빨라서 상황 분석에도 능하죠.","JPN":"人当たりもよく、頭の回転も早いため、状況分析にも長けています。","ENG":"He gets along with others and has the wits to quickly assess any situation.","TWN":"不僅平近易人，頭腦靈活，也很擅長分析情況。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"사실 평소에는 친하게 지내는 사원들도 많은 편입니다.","JPN":"実際のところ、普段は仲の良い社員も多い方です。","ENG":"In fact, there are many employees who are close to him.","TWN":"實際上，和很多員工關係也都很好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그런데?","JPN":"……では、何が問題なのだ？","ENG":"And?","TWN":"……那是？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"문제는 그 재능의 대부분을 게으름 피우는 곳에 쓴다는 점입니다.","JPN":"問題は、その才能の大部分を怠けることに使ってしまうことです。","ENG":"The problem is that he always uses his talents to slack off.","TWN":"問題是，他把才能大部分都用來偷懶了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"상황을 교묘하게 조작해서 어떻게든 힘든 임무에서 빠져나간다거나.......","JPN":"状況を巧みに利用し、辛い任務から抜け出そうとしたり……","ENG":"He manipulates the situation to somehow get away from doing difficult tasks...","TWN":"巧妙地操縱情況，想盡辦法從艱難的任務中脫身……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"본인이 충분히 해결할 수 있는 일도 적극적으로 개입하는 대신, 한 발 물러서서 구경만 하는 식이죠.","JPN":"本人が十分に解決できることであっても、積極的な介入はせず、一歩下がって俯瞰してしまうのです。","ENG":"Or he steps back and watches others take care of problems that he could have solved himself.","TWN":"就算是他完全能夠解決的事情，比起積極面對，他反而會選擇退一步觀察。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"직속 관리자가 스승님이 아닌 다른 사람이었다면 사흘 안에 스트레스로 쓰러져서 산업 재해 판정을 받아도 이상하지 않을 지경입니다.","JPN":"直属の管理者が師匠でなく他の人物であったなら、3日でストレスによって倒れてもおかしくないほどです。","ENG":"If his supervisor was someone other than the Master, the person would have been recognized as an industrial disaster victim after collapsing from stress within three days.","TWN":"如果直屬管理者不是師父，而是別人的話，那個人在三天內因壓力倒下，被判定為職業災害也不奇怪。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그, 그렇구만.","JPN":"……そ、そうなのか。","ENG":"I-I see.","TWN":"……原、原來如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 뭐하러 굳이 데리고 있는 건가?","JPN":"だとしたら、なぜ雇っているんだ？","ENG":"Then why are you keeping him?","TWN":"那為什麼一定要帶著他呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"차라리 깔끔하게 정리하는 게 서로를 위해서 좋을 수도.......","JPN":"いっそ、クビにしてしまえば互いにとって良いのではないか？","ENG":"It would be best for both of you to just fire him...","TWN":"不如把他開除掉，這對雙方都比較好吧……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"저도 마음 같아서는 그러고 싶지만.......","JPN":"私もそうしたいのは山々ですが……","ENG":"I wish I could do that...","TWN":"我心裡也是這麼想，也很想那麼做……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그나마 회사에서 비교적 안정적으로 활동하는 유일한 공인 B급 카운터입니다.","JPN":"比較的安定した活動を行える、唯一の公認B級カウンターなんです。","ENG":"But he is the only officially approved Grade B Counter who remains relatively active in the company.","TWN":"但他仍然是公司裡在工作比較穩定，唯一公認的B級制裁者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시윤 군이 아무리 속을 썩인다고 해도 스승님만 하지는 않을 테니까요.","JPN":"彼がいくら手のかかる社員とは言え、師匠よりかはマシですからね。","ENG":"And no matter how much trouble Shiyoon causes, he's not as bad as the Master.","TWN":"時雲君再怎麼任性，也沒有像師父那麼令我頭疼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......자네도 고생이 많군.","JPN":"……君も気苦労が多いな。","ENG":"It must have been really hard for you.","TWN":"……你還真是辛苦了呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런데 B급이라고 했나?","JPN":"しかし、B級だって？","ENG":"But did you say Grade B?","TWN":"但你說她是B級制裁者？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"지난번 작전에서 보여 준 모습을 보면 그 정도일 리가 없을 텐데.......","JPN":"前回の作戦の様子だと、そこまでには見えなかったが……","ENG":"That can't be right, considering how he performed in the last operation...","TWN":"在上次作戰中看到的樣子，應該不止那程度吧……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......관리국 카운터 등급은 대부분 CRF 출력을 기준으로 매기니까요.","JPN":"……管理局のカウンターのランクは、CRF出力を基準につけらますので。","ENG":"The Administration's Counter Grade is usually based on the CRF.","TWN":"……畢竟管理局對制裁者的評價，一般是以CRF輸出為基準。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시윤 군의 경우는 그 간극을 뛰어난 전투 센스와 잔머리로 극복하는 편입니다.","JPN":"アキヤマ・シリュウの場合、優れた戦闘センスと機転で短所を克服しています。","ENG":"Shiyoon makes up for the gap with his incredible combat skills and wits.","TWN":"周時雲的情況，是用敏銳的戰鬥直覺和小聰明來克服來這個差距。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어쨌든...... 공식적으로는 그렇습니다.","JPN":"とにかく……公式にはそうなっています。","ENG":"At least... that's what the official records say.","TWN":"總之……官方評測的結果是這樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"측정 결과에 문제가 있다고 생각하시면 관리국 검사기관에나 연락해 보시죠.","JPN":"測定結果に問題があると思われるのでしたら、管理局の検査機関へ連絡してみてはいかがでしょうか？","ENG":"If you believe there is a problem with his classification, please contact the Administration's Inspection Agency.","TWN":"如果您認為檢測結果有問題，可以試著連絡管理局的檢測機關。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......숨기는 게 많은 친구로군.","JPN":"……秘めたものが多いようだな。","ENG":"He has a lot of secrets.","TWN":"……看來是位秘密很多的朋友呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};